"""
MKT Christ in Every Verse — Zephaniah chapters 1-3 fill (52 missing verses; 3:14 already exists)
Run: python3 scripts/zc-christ-zephaniah-fill.py

Key decisions:
- Zephaniah is dominated by the Day of the LORD (used more here than any other prophet).
  Every verse connects to Christ as executor and absorber of that Day.
- 1:14-16 (Dies Irae source) — cross is where the Day of the LORD fell on Christ (Gal 3:13).
- 2:3 "seek righteousness, seek humility" — Christ IS the answer (1 Cor 1:30; Matt 11:29).
- 3:9 "pure language" — reversal of Babel; Pentecost partial; new creation final (Rev 7:9).
- 3:12 "humble and poor who take refuge in the name of the LORD" — Beatitudes (Matt 5:3-6).
- 3:17 YHWH warrior-savior who rejoices with singing — Christ's joy (John 15:11; Heb 12:2).
- directness labels: "A theme:", "A shadow:", "A type:", "A revelation of God:",
  "A direct anticipation:", "A fulfillment:"
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ZEPHANIAH = {
  "1": {
    "1": "<p>A theme: The superscription traces Zephaniah back four generations to King Hezekiah &mdash; the only writing prophet with established royal lineage. He prophesied during Josiah&rsquo;s reign (640-609 BCE), the last godly king before the Babylonian catastrophe. The genealogy frames the entire book: divine judgment is covenantal &mdash; YHWH holding the Davidic line to his own standard. Christ is the final Davidide who perfectly fulfills what the covenant-king was meant to be (Luke 1:32-33); his return is the Day of the LORD toward which all of Zephaniah&rsquo;s oracles point.</p>",
    "2": "<p>A theme: &lsquo;I will completely sweep away everything from the face of the land, declares the LORD.&rsquo; The opening judgment oracle is cosmic: total removal. The NT&rsquo;s eschatological form is 2 Peter 3:10-12: the heavens will pass away, the earth and its works exposed. But the gospel offers survival: those hidden in Christ (Col 3:3) are not swept away but brought through &mdash; the only shelter in the universal judgment.</p>",
    "3": "<p>A shadow: &lsquo;I will destroy both people and animals; I will destroy the birds of the sky and the fish of the sea.&rsquo; The reversal of creation order (birds, fish, animals, people destroyed) echoes Genesis 1 running backward. The NT new-creation motif runs in the opposite direction: the resurrection of Christ is the first fruit of the new creation that undoes Zephaniah&rsquo;s reversal (Rev 21:1-5; Rom 8:21: creation set free from bondage to corruption).</p>",
    "4": "<p>A revelation of God: &lsquo;I will stretch out my hand against Judah ... I will cut off the remnant of Baal and the name of the idol-worshiping priests.&rsquo; YHWH&rsquo;s outstretched hand against his own people &mdash; judgment rather than salvation &mdash; is the sobering covenant counterpart to the Exodus outstretched arm (Exod 6:6). The NT deepens the paradox: &ldquo;God did not spare his own Son but gave him up for us all&rdquo; (Rom 8:32). The hand stretched against Judah for idolatry is the same hand that delivered Christ for the world&rsquo;s sin.</p>",
    "5": "<p>A shadow: &lsquo;Those who bow on the rooftops to worship the host of heaven, and those who bow down and swear allegiance to the LORD but also swear by their king.&rsquo; The double allegiance &mdash; YHWH and astral powers &mdash; is the OT form of syncretism the NT refuses: &ldquo;No one can serve two masters&rdquo; (Matt 6:24); &ldquo;you cannot drink the cup of the Lord and the cup of demons&rdquo; (1 Cor 10:21). Christ demands undivided loyalty not as competition but because all alternatives are finite and doomed; only he survives the Day of the LORD.</p>",
    "6": "<p>A shadow: &lsquo;Those who have turned back from following the LORD, who do not seek the LORD or inquire of him.&rsquo; Passive apostasy &mdash; not active rebellion but simply stopping the seeking &mdash; is equally dangerous. &ldquo;If we neglect such a great salvation&rdquo; (Heb 2:3); &ldquo;the one who hears my word and does not do it is like a man who built a house on the ground without a foundation&rdquo; (Luke 6:49). Christ is the one who seeks the lost (Luke 15:4) because those who have stopped seeking can only be rescued by the one who keeps seeking them.</p>",
    "7": "<p>A direct anticipation: &lsquo;Be silent before the Lord GOD! The day of the LORD is near. The LORD has prepared a sacrifice and has set apart those he has invited.&rsquo; The sacrifice YHWH has prepared points to the cross, where YHWH himself provided the sacrifice (Gen 22:8). At Calvary the world was called to silence as the Day of the LORD arrived &mdash; the sacrifice was prepared, the invited guests are those the Father draws (John 6:44). The solemn feast-invitation becomes the wedding banquet in Christ (Matt 22:1-14).</p>",
    "8": "<p>A shadow: &lsquo;On the day of the LORD&rsquo;s sacrifice I will punish the officials and the king&rsquo;s sons and all who clothe themselves in foreign garments.&rsquo; The leaders clothed in foreign customs are condemned first &mdash; judgment begins at the household of God (1 Pet 4:17) because greater privilege entails greater accountability: &ldquo;from everyone who has been given much, much will be required&rdquo; (Luke 12:48). The NT warns against worldly conformity (Rom 12:2) using the same logic: abandoning covenantal identity for cultural assimilation is self-destruction.</p>",
    "9": "<p>A shadow: &lsquo;On that day I will punish everyone who leaps over the threshold, and those who fill their master&rsquo;s house with violence and fraud.&rsquo; Ritual transgression combined with economic violence &mdash; fraud filling the royal palace &mdash; is the OT linking of false religion and injustice. Jesus makes the same connection at the temple cleansing: &ldquo;My house shall be called a house of prayer, but you make it a den of robbers&rdquo; (Matt 21:13). Religious form that enables exploitation is the primary target of prophetic and apostolic rebuke.</p>",
    "10": "<p>A shadow: &lsquo;On that day a cry will be heard from the Fish Gate, a wail from the Mishneh district, and a loud crash from the hills.&rsquo; The Day of the LORD advancing through Jerusalem section by section &mdash; inescapable and total &mdash; anticipates the eschatological omnipresence of Christ&rsquo;s return: &ldquo;as the lightning comes from the east and shines as far as the west, so will be the coming of the Son of Man&rdquo; (Matt 24:27). No quarter of the city, no corner of the earth, is outside the reach of his coming &mdash; the same omnipresence marks judgment and salvation alike.</p>",
    "11": "<p>A shadow: &lsquo;Wail, O inhabitants of the Mortar! For all the traders are destroyed; all who weigh out silver are wiped out.&rsquo; The merchant district silenced anticipates Revelation&rsquo;s fall of Babylon (Rev 18:11-17) where merchants mourn sudden destruction. The NT alternative to commercial security is the treasure that cannot be seized: &ldquo;lay up for yourselves treasures in heaven, where neither moth nor rust destroys and where thieves do not break in and steal&rdquo; (Matt 6:20).</p>",
    "12": "<p>A shadow: &lsquo;At that time I will search Jerusalem with lamps, and I will punish the men who are complacent, who say in their hearts, &ldquo;The LORD will not do good, nor will he do ill.&rdquo;&rsquo; YHWH searching with lamps for hidden complacency echoes two NT images: the woman searching for her lost coin (Luke 15:8) &mdash; the same divine thoroughness applied to finding the lost; and Christ&rsquo;s letter to Laodicea (Rev 3:15-16) &mdash; lukewarm complacency judged. The searching lamp finds either the lost sheep or the indifferent self-deceiver.</p>",
    "13": "<p>A shadow: &lsquo;Though they build houses, they shall not inhabit them; though they plant vineyards, they shall not drink wine from them.&rsquo; The covenant curse of Deuteronomy 28:30 &mdash; build but not inhabit, plant but not enjoy &mdash; falls on Jerusalem. The NT fulfillment: Christ bore the covenant curse (Gal 3:13) so that in him the blessings are restored &mdash; &ldquo;houses and brothers and sisters and mothers and children and lands&rdquo; received now and eternal life in the age to come (Mark 10:30). The curse absorbed by Christ becomes the blessing enjoyed by his people.</p>",
    "14": "<p>A direct anticipation: &lsquo;The great day of the LORD is near &mdash; near and coming very quickly. The sound of the day of the LORD is bitter; even the warrior cries out in anguish.&rsquo; Zephaniah 1:14-16 is the biblical source for the medieval <em>Dies Irae</em> (Day of Wrath). The warrior who cries out in anguish on that Day points to Gethsemane: &ldquo;My soul is very sorrowful, even to death&rdquo; (Matt 26:38). Christ the mighty warrior cries out in anguish on the cross as the Day of the LORD falls on him &mdash; the warrior who absorbs the wrath so others are sheltered (Gal 3:13).</p>",
    "15": "<p>A direct anticipation: &lsquo;A day of wrath is that day, a day of distress and anguish, a day of ruin and devastation, a day of darkness and gloom, a day of clouds and thick darkness.&rsquo; The sevenfold description of the Day of the LORD. The Gospels describe Golgotha using this exact imagery: darkness fell over all the land from the sixth to the ninth hour (Matt 27:45) &mdash; the darkness of the Day of the LORD covering the cross. Christ bore the distress, anguish, ruin, and devastation of this Day on behalf of those who trust him.</p>",
    "16": "<p>A shadow: &lsquo;A day of trumpet blast and battle cry against the fortified cities and against the lofty battlements.&rsquo; The trumpet and battle cry of the Day of the LORD becomes the trumpet of the resurrection: &ldquo;the Lord himself will descend from heaven with a cry of command, with the voice of an archangel, and with the sound of the trumpet of God&rdquo; (1 Thess 4:16). The fortified cities that cannot withstand the divine assault become the strongholds of death and Hades that cannot withstand Christ: &ldquo;the gates of hell shall not prevail&rdquo; (Matt 16:18).</p>",
    "17": "<p>A shadow: &lsquo;I will bring distress on mankind, so that they walk like the blind, because they have sinned against the LORD; their blood shall be poured out like dust.&rsquo; The blinding that falls on the sinful &mdash; walking like the blind because they rejected the light &mdash; is the judgment Jesus reverses in his healing ministry (Luke 4:18; John 9). The blood poured out like dust on the Day of the LORD becomes the blood of Christ poured out for the forgiveness of sins (Matt 26:28) &mdash; the same blood, offered now in mercy rather than judgment.</p>",
    "18": "<p>A shadow: &lsquo;Neither their silver nor their gold will be able to deliver them on the day of the LORD&rsquo;s wrath.&rsquo; The total inadequacy of wealth on the Day of the LORD is the OT ground for the NT&rsquo;s announcement of a different ransom: &ldquo;you were ransomed from the futile ways inherited from your forefathers, not with perishable things such as silver or gold, but with the precious blood of Christ, like that of a lamb without blemish or spot&rdquo; (1 Pet 1:18-19). The silver and gold that cannot deliver in Zephaniah are explicitly contrasted with Christ&rsquo;s blood in 1 Peter as the true ransom.</p>"
  },
  "2": {
    "1": "<p>A shadow: &lsquo;Come together, gather yourselves, O shameless nation.&rsquo; The call to gather before judgment &mdash; assemble before the decree arrives &mdash; is the OT form of eschatological urgency the gospel carries: &ldquo;Behold, now is the favorable time; behold, now is the day of salvation&rdquo; (2 Cor 6:2). The gathering called for before the Day arrives becomes the gathering of the church (Heb 10:25) and the final gathering of the elect (Matt 24:31). The urgency of Zephaniah&rsquo;s call is the urgency of every gospel invitation.</p>",
    "2": "<p>A shadow: &lsquo;Before the appointed decree arrives &mdash; before the day passes like chaff &mdash; before the LORD&rsquo;s burning anger comes upon you.&rsquo; The fourfold &ldquo;before&rdquo; &mdash; four urgent warnings stacked together &mdash; is the prophetic rhetoric of last-hour urgency. The NT has the same grammar: &ldquo;seek the Lord while he may be found; call upon him while he is near&rdquo; (Isa 55:6); &ldquo;Today, if you hear his voice, do not harden your hearts&rdquo; (Heb 3:7-8). The interval between now and the Day is the space of gospel invitation &mdash; Christ is offered now; after the Day, the decree is fixed.</p>",
    "3": "<p>A direct anticipation: &lsquo;Seek the LORD, all you humble people of the land who have carried out his commands. Seek righteousness; seek humility. Perhaps you will be sheltered on the day of the LORD&rsquo;s anger.&rsquo; The call to seek YHWH, righteousness, and humility as the only shelter from the Day of wrath. Paul&rsquo;s answer: &ldquo;By God&rsquo;s doing you are in Christ Jesus, who has become for us wisdom from God, and righteousness, and sanctification, and redemption&rdquo; (1 Cor 1:30). The three things Zephaniah calls the humble to seek are found in Christ: he is YHWH incarnate, our righteousness (2 Cor 5:21), and the meek and lowly one (Matt 11:29).</p>",
    "4": "<p>A shadow: &lsquo;For Gaza shall be deserted, and Ashkelon shall become a desolation.&rsquo; The judgment oracles against the Philistine cities are the OT pattern for comprehensive judgment of the nations. The same territory Jesus tours (Mark 7:24-8:10), extending healing to Gentiles in the regions of Tyre and Sidon. What was judgment for the nations becomes gospel invitation: the same outstretched divine hand that swept the Philistine coast also extends to Gentile sick and hungry crowds in Christ.</p>",
    "5": "<p>A shadow: &lsquo;Woe to you inhabitants of the seacoast, you nation of the Cherethites!&rsquo; The woe against the Cherethites (Cretans) points to the eventual extension of gospel light to exactly these regions. Paul planted churches throughout the Aegean coastlands; Titus ministered in Crete (Tit 1:5); Cretan pilgrims heard Peter at Pentecost (Acts 2:11). The word of the LORD that is &ldquo;against&rdquo; the nations in judgment becomes the word &ldquo;for&rdquo; the nations in the gospel &mdash; the same divine word, now offering shelter through the cross.</p>",
    "6": "<p>A theme: &lsquo;And you, O seacoast, shall be pastures, with meadows for shepherds and folds for flocks.&rsquo; The desolated coastal land becoming sheepfolds &mdash; ruin transformed into pastoral peace &mdash; is the OT pattern for new creation. Jesus self-describes as the Good Shepherd whose people &ldquo;will go in and out and find pasture&rdquo; (John 10:9). The sheepfolds of a restored coastal plain become the metaphor for the church gathered by Christ into safety and abundance.</p>",
    "7": "<p>A shadow: &lsquo;For the LORD their God will visit them and restore their fortunes.&rsquo; YHWH &ldquo;visiting&rdquo; his people (<em>paqad</em>) to restore them is the OT formula for divine intervention. Zechariah&rsquo;s <em>Benedictus</em> (Luke 1:68) applies this directly to the incarnation: &ldquo;Blessed be the Lord God of Israel, for he has visited and redeemed his people.&rdquo; The God who visited his people to restore their land visits in the incarnation to restore their souls.</p>",
    "8": "<p>A shadow: &lsquo;I have heard the taunts of Moab and the revilings of the Ammonites.&rsquo; YHWH hearing the taunts of the nations &mdash; divine advocacy for his people &mdash; is the OT pattern developed into Christ&rsquo;s intercession: &ldquo;Christ Jesus is the one who died &mdash; more than that, who was raised &mdash; who is at the right hand of God, who indeed is interceding for us&rdquo; (Rom 8:34). The God who heard Moab&rsquo;s taunt now acts through the risen Christ who hears every accusation against his people and answers it.</p>",
    "9": "<p>A shadow: &lsquo;Moab shall become like Sodom, and the Ammonites like Gomorrah.&rsquo; Moab and Ammon like Sodom &mdash; the ultimate OT image of complete divine judgment. Jesus uses Sodom-and-Gomorrah as the standard of judgment exceeded by those who reject the gospel (Matt 10:15; 11:24): the towns that reject the apostles face greater judgment than Sodom. The only escape from the antitype is sheltering in Christ, who himself bore a Sodom-like judgment at the cross (Lam 4:6: Jerusalem&rsquo;s fall is described as greater than Sodom&rsquo;s punishment).</p>",
    "10": "<p>A revelation of God: &lsquo;This shall be their lot in return for their pride, because they taunted and boasted against the people of the LORD of hosts.&rsquo; Pride &mdash; the root sin that generates contempt for YHWH&rsquo;s people &mdash; is definitively dismantled at the cross: &ldquo;God opposes the proud but gives grace to the humble&rdquo; (Jas 4:6). Christ came in ultimate humility (Phil 2:6-8: not grasping equality with God but emptying himself) and was exalted. The proud nations that taunt are undone; Christ&rsquo;s humility becomes his people&rsquo;s exaltation.</p>",
    "11": "<p>A direct anticipation: &lsquo;The LORD will be awesome against them; for he will famish all the gods of the earth, and to him shall bow down, each in its place, all the lands of the nations.&rsquo; The universal bowing of all nations is the OT basis for the NT&rsquo;s universal Lordship of Christ: &ldquo;at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue confess that Jesus Christ is Lord&rdquo; (Phil 2:10-11). The &ldquo;famishing&rdquo; of the gods is the ongoing work of the gospel: wherever Christ is proclaimed, idols lose their hold.</p>",
    "12": "<p>A shadow: &lsquo;You also, O Cushites, shall be slain by my sword.&rsquo; Judgment reaching to the farthest known peoples is met by the gospel reaching the same peoples: the Ethiopian eunuch (Acts 8:26-39) is the first person from Cush named as receiving the gospel. Philip explains that Isaiah 53 speaks of Jesus, and the eunuch is baptized. The divine sword that came in judgment against Cush gives way to the divine word that brought salvation to a Cushite official reading Isaiah on the road to Gaza.</p>",
    "13": "<p>A shadow: &lsquo;And he will stretch out his hand against the north and destroy Assyria, and he will make Nineveh a desolation, a dry waste like the desert.&rsquo; Nineveh&rsquo;s destruction (612 BCE) is the historical type for every empire overthrown by divine action. Revelation&rsquo;s Babylon follows the same pattern (Rev 18:8: &ldquo;in a single day her plagues will come&rdquo;). Christ&rsquo;s kingdom replaces every empire: &ldquo;the kingdom of the world has become the kingdom of our Lord and of his Christ, and he shall reign forever and ever&rdquo; (Rev 11:15).</p>",
    "14": "<p>A shadow: &lsquo;Herds shall lie down in her midst; even the owl and the hedgehog shall lodge in her capitals.&rsquo; The desolation of Nineveh &mdash; wild animals nesting in royal buildings &mdash; is the OT image of ultimate reversal. The desolated temple Jesus announces (Matt 23:38: &ldquo;your house is left to you desolate&rdquo;) is the NT application. But where Nineveh&rsquo;s desolation was permanent, the temple&rsquo;s desolation is penultimate &mdash; the greater temple (Christ&rsquo;s body, John 2:19-21) is raised, and the new Jerusalem (Rev 21) permanently replaces all desolated cities.</p>",
    "15": "<p>A shadow: &lsquo;This is the exultant city that lived securely, that said in her heart, &ldquo;I am, and there is no one else.&rdquo;&rsquo; Nineveh appropriating divine uniqueness (&ldquo;I am, and there is no one else&rdquo; &mdash; the very words YHWH uses in Isaiah 45:6) is the ultimate form of idolatrous hubris. The NT application: every power that arrogates divine uniqueness is measured against the true I AM (John 8:58) who is Christ. The proud city that said &ldquo;I am&rdquo; is desolate; the one who IS eternally (Rev 1:8) reigns forever.</p>"
  },
  "3": {
    "1": "<p>A shadow: &lsquo;Woe to the rebellious, defiled, oppressing city!&rsquo; The triple woe against Jerusalem &mdash; rebellious, defiled, oppressive &mdash; is the same accusation Jesus makes in Matthew 23&rsquo;s seven woes. Christ enters the woe-city and becomes the recipient of the woe (Gal 3:13: he became a curse for us) so that its inhabitants might be freed from it. He was neither rebellious, nor defiled, nor oppressive: &ldquo;he committed no sin, neither was deceit found in his mouth&rdquo; (1 Pet 2:22).</p>",
    "2": "<p>A shadow: &lsquo;She has not listened to any voice; she has accepted no correction. She has not trusted in the LORD; she has not drawn near to her God.&rsquo; The four-part indictment &mdash; deaf, unteachable, faithless, distant &mdash; is the OT profile of covenant failure applied to Christ&rsquo;s generation: &ldquo;He came to his own, and his own people did not receive him&rdquo; (John 1:11). In Christ all four failures are reversed: he listened perfectly (John 5:30), accepted the Father&rsquo;s will including the cross (Luke 22:42), trusted absolutely (Heb 2:13), and was in constant communion with the Father (John 10:30).</p>",
    "3": "<p>A shadow: &lsquo;Her officials within her are roaring lions; her judges are wolves of the evening that leave no bone until morning.&rsquo; The predatory leaders &mdash; lion-officials and wolf-judges &mdash; are the anti-shepherds against whom Christ sets himself as the Good Shepherd who lays down his life for the sheep (John 10:11): the anti-predator who is himself consumed so the flock is spared. The leaders who devour in Zephaniah are judged by the shepherd who is devoured for the sheep.</p>",
    "4": "<p>A shadow: &lsquo;Her prophets are fickle, treacherous men; her priests profane what is holy; they do violence to the law.&rsquo; The corrupt prophets and priests answered by Christ who fulfills all three offices: the true prophet (Deut 18:15; Acts 3:22) who speaks only what the Father gives him (John 12:49); the true priest (Heb 5:5-6) who does not profane but fulfills the holy; the true interpreter of the law (Matt 5:17: I have not come to abolish the law but to fulfill it).</p>",
    "5": "<p>A revelation of God: &lsquo;The LORD within her is righteous; he does no wrong. Morning after morning he brings his justice to light; he never fails.&rsquo; YHWH&rsquo;s morning-by-morning faithfulness contrasted with Jerusalem&rsquo;s shameless injustice is the OT theodicy: God is righteous; his people are not. The NT resolution: &ldquo;God made him who had no sin to be sin for us, so that in him we might become the righteousness of God&rdquo; (2 Cor 5:21). The righteous God of Zephaniah 3:5 does not compromise his righteousness &mdash; he transfers it to his people through Christ.</p>",
    "6": "<p>A shadow: &lsquo;I have cut off nations; their battlements are in ruins; I have laid waste their streets.&rsquo; YHWH rehearsing his judgments against the nations as a warning to Jerusalem is the eschatological pedagogy Paul extends: &ldquo;Now these things happened to them as an example, but they were written down for our instruction&rdquo; (1 Cor 10:11). The desolated cities of history are sermons in stone; the cross is the ultimate lesson written in flesh &mdash; what the Day of the LORD does, borne by Christ so his people learn without perishing.</p>",
    "7": "<p>A shadow: &lsquo;I said, &ldquo;Surely you will fear me; you will accept correction.&rdquo; But all the more they were eager to make all their deeds corrupt.&rsquo; The divine expectation of repentance repeatedly disappointed is the OT pattern Jesus echoes in the parable of the tenants: the owner sends servants expecting fruit; each is rejected; finally he sends his son (Matt 21:33-39). The divine patience that kept expecting response reached its ultimate expression in the Son &mdash; and the rejection of the Son became the means of redemption (Acts 4:27-28).</p>",
    "8": "<p>A direct anticipation: &lsquo;&ldquo;Therefore wait for me, declares the LORD, for the day when I rise up to seize the prey.&rdquo;&rsquo; &ldquo;Wait for me&rdquo; (<em>chakwu li</em>) &mdash; YHWH calling his people to patient expectation &mdash; is the OT command of eschatological patience. Paul translates this: &ldquo;we ourselves groan inwardly as we wait eagerly for adoption as sons, the redemption of our bodies&rdquo; (Rom 8:23). The rising of YHWH to act points to the resurrection &mdash; Christ rising to seize what death held and gather the nations (Matt 28:18-20). The &ldquo;wait for me&rdquo; of Zephaniah is the &ldquo;come, Lord Jesus&rdquo; of Revelation 22:20.</p>",
    "9": "<p>A fulfillment: &lsquo;At that time I will give the peoples a pure language, so that all of them may call on the name of the LORD and serve him with one purpose.&rsquo; The pure language given to all peoples is the reversal of Babel (Gen 11:7). Pentecost is the partial fulfillment: all nations hear the gospel in their own language (Acts 2:8-11) and call on the name of the Lord (Acts 2:21). The final fulfillment: &ldquo;a great multitude from every nation, from all tribes and peoples and languages, standing before the throne and before the Lamb&rdquo; (Rev 7:9) &mdash; united worship, one name, one purpose.</p>",
    "10": "<p>A shadow: &lsquo;From beyond the rivers of Cush my worshipers, the daughter of my dispersed ones, shall bring my offering.&rsquo; Worshippers from the farthest reaches of the world bringing offerings to YHWH &mdash; the OT eschatological vision of universal worship beginning in Acts (the Ethiopian eunuch, Acts 8) and consummating in Revelation (worshipers from every nation, Rev 5:9-10). Christ&rsquo;s commission extends exactly to these &ldquo;ends of the earth&rdquo; (Acts 1:8).</p>",
    "11": "<p>A shadow: &lsquo;On that day you shall not be put to shame because of the deeds by which you have rebelled against me; for then I will remove from your midst your proudly exultant ones.&rsquo; The shame removed &mdash; no longer condemned for rebellion &mdash; is the NT&rsquo;s &ldquo;there is now no condemnation for those who are in Christ Jesus&rdquo; (Rom 8:1). The proud removed from the holy mountain anticipates the purification of the new Jerusalem: &ldquo;nothing unclean will ever enter it&rdquo; (Rev 21:27). Christ&rsquo;s work removes both the guilt and the residual pride of his people (Phil 1:6).</p>",
    "12": "<p>A direct anticipation: &lsquo;I will leave in your midst a people who are humble and poor; they will find refuge in the name of the LORD.&rsquo; The remnant who survive the Day are specifically the humble and poor (<em>ani</em> and <em>dal</em>). This is the OT template for the Beatitudes: &ldquo;Blessed are the poor in spirit, for theirs is the kingdom of heaven&rdquo; (Matt 5:3); &ldquo;Blessed are the meek, for they shall inherit the earth&rdquo; (Matt 5:5). The &ldquo;name of the LORD&rdquo; in which they find refuge is the name of Jesus: &ldquo;there is no other name under heaven given among men by which we must be saved&rdquo; (Acts 4:12).</p>",
    "13": "<p>A shadow: &lsquo;They shall do no injustice and speak no lies, nor shall there be found in their mouth a deceitful tongue. For they shall graze and lie down, and none shall make them afraid.&rsquo; The remnant without injustice or deceit, lying down in peace &mdash; the OT profile of the redeemed community. Revelation applies this to the 144,000 (Rev 14:5: &ldquo;in their mouth no lie was found, for they are blameless&rdquo;). Christ is the pattern: &ldquo;no deceit was found in his mouth&rdquo; (1 Pet 2:22), and his people are being conformed to the same truthfulness (Eph 4:15: speaking the truth in love).</p>",
    "15": "<p>A direct anticipation: &lsquo;The LORD has taken away the judgments against you; he has cleared away your enemies. The King of Israel, the LORD, is in your midst; you shall never again fear evil.&rsquo; Three declarations: judgment removed, enemies cleared, the King of Israel &mdash; YHWH himself &mdash; present in the midst. The NT fulfillment is the incarnation: (1) &ldquo;there is now no condemnation&rdquo; (Rom 8:1); (2) &ldquo;he disarmed the rulers and authorities&rdquo; (Col 2:15); (3) &ldquo;the Word became flesh and dwelt among us&rdquo; (John 1:14). The King of Israel present in the midst is specifically Jesus &mdash; YHWH incarnate, whose presence makes fear impossible (1 John 4:18).</p>",
    "16": "<p>A shadow: &lsquo;On that day it shall be said to Jerusalem: &ldquo;Do not fear, O Zion; do not let your hands go limp.&rdquo;&rsquo; The eschatological &ldquo;do not fear&rdquo; addressed to restored Zion is the most frequent command in the Bible, spoken supremely by Jesus: &ldquo;Do not be afraid, little flock, for it is your Father&rsquo;s good pleasure to give you the kingdom&rdquo; (Luke 12:32); &ldquo;Fear not, I am the first and the last and the living one&rdquo; (Rev 1:17-18). Hebrews 12:12 uses the same idiom: &ldquo;lift your drooping hands and strengthen your weak knees.&rdquo; Christ&rsquo;s resurrection is the ground for this strengthening.</p>",
    "17": "<p>A revelation of God: &lsquo;The LORD your God is in your midst &mdash; a warrior who saves. He will rejoice over you with joy; he will be still in his love; he will exult over you with singing.&rsquo; Zephaniah 3:17 is the OT&rsquo;s most intimate portrait of divine joy: YHWH not merely tolerating his people but singing over them. The NT&rsquo;s three forms of this joy: (1) Jesus&rsquo;s own joy in his disciples &mdash; &ldquo;that my joy may be in you, and that your joy may be full&rdquo; (John 15:11); (2) the Father&rsquo;s joy over the returning prodigal (Luke 15:20); (3) the eschatological joy at the wedding supper of the Lamb (Rev 19:7). The warrior who saves and rejoices is Christ &mdash; the divine warrior whose warfare is love and whose victory song is the resurrection.</p>",
    "18": "<p>A shadow: &lsquo;I will gather those of you who grieve over the appointed festival, so that you will no longer suffer reproach.&rsquo; The gathering of those who grieve over missed sacred festivals &mdash; the longing to worship that exile has blocked &mdash; is answered by Christ&rsquo;s invitation: &ldquo;Come to me, all who labor and are heavy laden, and I will give you rest&rdquo; (Matt 11:28). He is himself the festival (1 Cor 5:7-8: Christ our Passover lamb has been sacrificed) &mdash; all the appointed feasts are fulfilled in him, and all mourning over missed worship is answered in his presence.</p>",
    "19": "<p>A shadow: &lsquo;Behold, at that time I will deal with all your oppressors. And I will save the lame and gather the outcast, and I will change their shame into praise and renown in all the earth.&rsquo; The divine advocacy for the lame and outcast &mdash; shame turned to praise &mdash; is the eschatological vision Jesus enacts in his healing ministry: he heals the lame (Matt 11:5), gathers the outcast (Luke 15), and publicly honors the shamed (the hemorrhaging woman honored as &ldquo;daughter,&rdquo; Mark 5:34). Every healing is a firstfruit of the final gathering when all shame becomes praise.</p>",
    "20": "<p>A fulfillment: &lsquo;At that time I will bring you home, when I gather you together; I will give you a name and praise among all the peoples of the earth, when I restore your fortunes before your eyes, says the LORD.&rsquo; Zephaniah closes with homecoming. The NT&rsquo;s form: &ldquo;In my Father&rsquo;s house are many rooms ... I go to prepare a place for you. And ... I will come again and will take you to myself&rdquo; (John 14:2-3). The &ldquo;home&rdquo; Zephaniah promises is the Father&rsquo;s house Jesus prepares; the &ldquo;name given to all peoples&rdquo; is the name above every name (Phil 2:9-11); the restored fortunes are the inheritance &ldquo;imperishable, undefiled, and unfading, kept in heaven&rdquo; (1 Pet 1:4).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'zephaniah')
    merge_comm(existing, ZEPHANIAH)
    save_comm('mkt-christ', 'zephaniah', existing)
    print('Zephaniah 1-3 mkt-christ fill complete.')

